import Foundation
import Alamofire
import SwiftyJSON

struct Stock {
    let symbol: String
    let name: String
    let price: Double
}

class APIManager {
    private static let apiKey = "YOUR_API_KEY"

    static func getStockPrice(symbol: String, completion: @escaping (Double?, Error?) -> Void) {
        let url = "https://api.iextrading.com/1.0/\(symbol)/stock/market/batch?types=price"
        Alamofire.request(url).responseJSON { response in
            if let data = response.data {
                do {
                    let json = try JSON(data: data)
                    if let price = json["YOUR_SYMBOL"].double {
                        completion(price, nil)
                    } else {
                        completion(nil, NSError(domain: "APIError", code: -1, userInfo: nil))
                    }
                } catch {
                    completion(nil, error as NSError)
                }
            } else {
                completion(nil, NSError(domain: "NetworkError", code: -2, userInfo: nil))
            }
        }
    }
}

class TradeManager {
    private var stocks = [Stock]()

    func buyStock(stockSymbol: String, quantity: Int, completion: @escaping (Error?) -> Void) {
        APIManager.getStockPrice(symbol: stockSymbol) { price, error in
            if let price = price, let quantity = quantity {
                self.stocks.append(Stock(symbol: stockSymbol, name: "Stock \(stockSymbol)", price: price))
                completion(nil)
            } else {
                completion(error)
            }
        }
    }
}